#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    unordered_map<int, int> prefix_sum;
    prefix_sum[0] = -1;
    int curr_sum = 0;
    int max_len = 0;
    for(int i = 0; i < n; i++){
        curr_sum += nums[i];
        if(prefix_sum.find(curr_sum) != prefix_sum.end()){
            max_len = max(max_len, i - prefix_sum[curr_sum]);
        } else {
            prefix_sum[curr_sum] = i;
        }
    }
    cout << max_len << endl;
    return 0;
}
